#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using arithmetic deserialization
    adaptor >> packet.packet_id;

    // Read username using prefixed adaptor
    adaptor >> hexi::prefixed(packet.username);

    // Read score count and then use read_container to read scores vector
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.read_container(packet.scores, score_count);

    // Read metadata using null_terminated adaptor
    adaptor >> hexi::null_terminated(packet.metadata);

    // Calculate padding and skip remaining bytes
    const auto total_read = adaptor.total_read();
    const auto bytes_to_skip = buffer.size() - total_read;
    if (bytes_to_skip > 0) {
        adaptor.skip(bytes_to_skip);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    PacketInfo info;

    // Use span() to get packet_id (first 4 bytes)
    info.packet_id = *reinterpret_cast<const uint32_t*>(buffer.data());

    // Use prefixed adaptor to read username (string_view with length prefix)
    adaptor.skip(sizeof(uint32_t)); // Skip the length prefix we already read
    adaptor >> hexi::prefixed(info.username);

    // Read score count and skip scores data
    uint32_t score_count;
    adaptor >> score_count;
    const auto bytes_to_skip = score_count * sizeof(uint32_t);
    adaptor.skip(bytes_to_skip);

    return info;
}
