bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer_adaptor for the provided buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Check available space using buffer_adaptor's size()
    auto available_space = adaptor.size();

    // Calculate total required space: sizeof(header) + items.size() * sizeof(uint32_t)
    auto required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // If insufficient space, return false
    if (available_space < required_space) {
        return false;
    }

    // Get the write pointer using buffer_adaptor's write_ptr()
    auto* write_ptr = adaptor.write_ptr();

    // Write the header using memcpy or similar
    std::memcpy(write_ptr, &header, sizeof(header));

    // Advance write pointer past the header
    write_ptr += sizeof(header);

    // Write container data using binary_stream's write_container
    hexi::binary_stream stream(adaptor);
    stream.write_container(items);

    return true;
}
